#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[1] - y[1];
}

long long power(long long x, long long y) {
    long long res = 1;
    while (y > 0) {
        if (y & 1)
            res = (res * x) % MOD;
        y = y >> 1;
        x = (x * x) % MOD;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, MOD - 2);
}

long long nCr(long long n, long long r) {
    if (r > n)
        return 0;
    long long fac[n + 1];
    fac[0] = 1;
    for (int i = 1; i <= n; i++)
        fac[i] = (fac[i - 1] * i) % MOD;
    return (fac[n] * modInverse(fac[r]) % MOD * modInverse(fac[n - r]) % MOD) % MOD;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int segments[N][2];
        for (int i = 0; i < N; i++)
            scanf("%d %d", &segments[i][0], &segments[i][1]);
        qsort(segments, N, sizeof(segments[0]), compare);
        long long count = 0;
        for (int i = 0; i < N; i++) {
            int j = i + 1;
            while (j < N && segments[j][0] <= segments[i][1])
                j++;
            if (j - i >= K)
                count = (count + nCr(j - i, K)) % MOD;
        }
        printf("%lld\n", count);
    }
    return 0;
}

