            long count = 0;
            for (int i = 0; i < N; i++) {
                int j = i + 1;
                while (j < N && segments[j][0] <= segments[i][1])
                    j++;
                if (j - i >= K)
                    count = (count + nCr(j - i, K)) % MOD;
            }
            System.out.println(count);
        }
    }
    public static long power(long x, long y) {
        long res = 1;
        while (y > 0) {
            if (y % 2 == 1)
                res = (res * x) % MOD;
            y = y >> 1;
            x = (x * x) % MOD;
        }
        return res;
    }
