import sys
MOD = 1000000007

def power(x, y):
    res = 1
    while y > 0:
        if y % 2 == 1:
            res = (res * x) % MOD
        y = y >> 1
        x = (x * x) % MOD
    return res

def modInverse(n):
    return power(n, MOD - 2)

def nCr(n, r):
    if r > n:
        return 0
    fac = [1] * (int(n) + 1)
    for i in range(1, int(n) + 1):
        fac[i] = (fac[i - 1] * i) % MOD
    return (fac[int(n)] * modInverse(fac[int(r)]) % MOD * modInverse(fac[int(n) - int(r)]) % MOD) % MOD

t = int(input())
for _ in range(t):
    n, k = map(int, input().split())
    segments = [list(map(int, input().split())) for _ in range(n)]
    segments.sort(key=lambda x: x[1])
    count = 0
    for i in range(n):
        j = i + 1
        while j < n and segments[j][0] <= segments[i][1]:
            j += 1
        if j - i >= k:
            count = (count + nCr(j - i, k)) % MOD
    print(count)

